// ── CREW MEMBER 2 (man2.png, editable via M key) ──
window.createHelmsman2 = function(bridgeRoomGroup, extraEditables) {
  const BRIDGE_ROOM_R = window.BRIDGE_ROOM_R || 280;
  const _img2 = new Image();  _img2.src='data:image/png;base64,';
      _img2.onload = function() {
    const tex2 = new THREE.Texture(_img2); tex2.needsUpdate = true;
    const spriteH2 = 94, spriteW2 = spriteH2 * (438/680);
    const crewMesh2 = new THREE.Mesh(
      new THREE.PlaneGeometry(spriteW2, spriteH2),
      new THREE.MeshBasicMaterial({ map: tex2, transparent: true, alphaTest: 0.1 })
    );
    crewMesh2.name = 'crew_man2';
    crewMesh2.position.set(30, spriteH2 / 2, BRIDGE_ROOM_R - 50);
    crewMesh2.rotation.y = 0;
    bridgeRoomGroup.add(crewMesh2);
    extraEditables.push(crewMesh2);
  };
};
